from playwright.sync_api import Page, expect

class LoginPage:
    def __init__(self, page: Page) -> None:
        self.page = page
        self.email_input = page.get_by_label('Email')
        self.password_input = page.get_by_label('Password')
        self.submit_button = page.get_by_role('button', name='Log in')
        self.error_message = page.get_by_role('alert')

    def goto(self) -> 'LoginPage':
        self.page.goto('/login')
        return self

    def login(self, email: str, password: str) -> None:
        self.email_input.fill(email)
        self.password_input.fill(password)
        self.submit_button.click()

    def get_error_text(self) -> str:
        return self.error_message.inner_text()


# test_login.py
def test_invalid_credentials_shows_error(page: Page):
    login_page = LoginPage(page)
    login_page.goto()
    login_page.login('user@example.com', 'wrongpass')
    assert login_page.get_error_text() == 'Invalid email or password'

